import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import 'app_button.dart';
class AuthRequiredSheet extends StatelessWidget{final String redirect;const AuthRequiredSheet({super.key,required this.redirect});@override Widget build(BuildContext c)=>Padding(padding:const EdgeInsets.all(20),child:Column(mainAxisSize:MainAxisSize.min,children:[const Text('Login or Register to Submit Prediction',style:TextStyle(fontSize:18,fontWeight:FontWeight.bold)),const SizedBox(height:12),AppButton(label:'Login',onPressed:()=>c.go('/login?redirect=${Uri.encodeComponent(redirect)}')),AppButton(label:'Register',outlined:true,onPressed:()=>c.go('/register?redirect=${Uri.encodeComponent(redirect)}'))]));}
